def store_info_in_header(info_type: str, info_content: str, header: Dict[str, str]) -> Dict[str, str]:
    valid_types = {'lang', 'encoding', 'cache'}
    if info_type not in valid_types:
        return header
    new_header = header.copy()
    if info_type == 'lang':
        new_header['Accept-Language'] = info_content
    elif info_type == 'encoding':
        new_header['Accept-Encoding'] = info_content
    elif info_type == 'cache':
        new_header['Cache-Control'] = info_content
    return new_header

